// PTZ operation log display
function ptzLog(msg, type='info') {
    const box = document.getElementById('ptzLogBox');
    if (!box) { console.warn('[ptzLog] ptzLogBox not found'); return; }
    const time = new Date().toLocaleTimeString();
    const colors = {
        'info': '#8b949e',
        'success': '#3fb950',
        'error': '#f85149',
        'warning': '#d29922',
        'debug': '#58a6ff'
    }; 
    const icons = {
        'info': '○',
        'success': '●',
        'error': '×',
        'warning': '△',
        'debug': '◇'
    }; 
    const color = colors[type] || '#8b949e';
    const icon = icons[type] || '○';
    const entry = document.createElement('div');
    entry.style.cssText = 'color:' + color + ';margin:2px 0;padding:2px 8px;font-size:13px;font-family:monospace';
    entry.textContent = '[' + time + '] ' + icon + ' ' + msg;
    box.insertBefore(entry, box.firstChild);
    if (box.children.length > 50) box.removeChild(box.lastChild);
    console.log('[ptzLog]', msg, type);
}
